const CONFIG={DB_NAME:'anti-cache-db',DB_VERSION:1,STORE_NAME:'file-metadata',LIST_URL:'file-list.json',CACHE_PREFIX:'app-static-v',MAX_RETRIES:3,RETRY_DELAY_MS:1000,MANIFEST_TIMEOUT_MS:10000,FILE_TIMEOUT_MS:15000,CONCURRENT_FETCH_LIMIT:5};let dbConnection=null;self.addEventListener('install',event=>{self.skipWaiting();event.waitUntil(installHandler().catch(err=>console.error('[SW] Install failed:',err)))});self.addEventListener('activate',event=>{event.waitUntil((async()=>{await self.clients.claim();await cleanupOldCaches();console.log('[SW] Activated')})().catch(err=>console.error('[SW] Activate failed:',err)))});self.addEventListener('fetch',event=>{const{request}=event;const url=new URL(request.url);if(isManifest(url)){event.respondWith(handleManifestFetch())}else if(isStaticAsset(url)){event.respondWith(handleStaticRequest(request))}else if(request.mode==='navigate'){event.respondWith(handleNavigationRequest(request))}else{event.respondWith(fetch(request))}});async function installHandler(){let fileList;try{const db=await getDBConnection();const latestVersion=await getLatestVersion(db);fileList=await fetchWithTimeout(CONFIG.LIST_URL,CONFIG.MANIFEST_TIMEOUT_MS,true);if(!fileList.version||fileList.version<=latestVersion){return}await updateMetadata(db,fileList);await precacheFiles(fileList.files);console.log(`[SW] Cached v${fileList.version }`)}catch(error){console.error('[SW] Critical install error:',error)}}async function handleStaticRequest(request){const cacheName=getConfigCacheName(getVersionFromUrl(new URL(request.url)));const cache=await caches.open(cacheName);const cached=await cache.match(request);if(cached){maybeRefreshBackground(request,cache);return cached}return fetchAndCacheNetwork(request,cache)}async function handleNavigationRequest(request){const cacheName=`${CONFIG.CACHE_PREFIX }-latest`;const cache=await caches.open(cacheName);const cached=await cache.match(request);cacheMatchAndUpdate(request,cache).catch(()=>{});return cached||fetch(request).then(res=>{res.ok&&cache.put(request,res.clone());return res}).catch(()=>caches.match('/offline.html'))}function getConfigCacheName(version){return `${CONFIG.CACHE_PREFIX }-${version||'latest'}`}function getVersionFromUrl(url){const m=url.pathname.match(/\/app-static-v(\d+)\//);return m?m[1]:null}function isManifest(url){return url.pathname.endsWith(CONFIG.LIST_URL)}function isStaticAsset(url){return/\.(?:js|css|woff2?|ttf|png|jpe?g|gif|svg)(\?|#|$)/i.test(url.href)}async function precacheFiles(files){const version=Math.max(...files.map(f=>f.version)||[0])||Date.now();const cacheName=getConfigCacheName(version);const cache=await caches.open(cacheName);const chunks=[];for(let i=0;i<files.length;i+=CONFIG.CONCURRENT_FETCH_LIMIT){chunks.push(files.slice(i,i+CONFIG.CONCURRENT_FETCH_LIMIT))}for(const chunk of chunks){await Promise.allSettled(chunk.map(f=>fetchAndRetryFile(f.url,cache)))}}async function fetchAndRetryFile(fileUrl,cache,attempt=1){try{const res=await fetchWithTimeout(fileUrl,CONFIG.FILE_TIMEOUT_MS);if(!res.ok){throw new Error(`HTTP ${res.status }`)}await cache.put(fileUrl,res.clone())}catch(e){if(attempt<CONFIG.MAX_RETRIES){await sleep(CONFIG.RETRY_DELAY_MS*attempt);return fetchAndRetryFile(fileUrl,cache,attempt+1)}console.warn(`[SW] Failed: ${ fileUrl }`)}}async function fetchAndCacheNetwork(request,cache){try{const response=await fetch(request);if(response.ok){await cache.put(request,response.clone())}return response}catch{return caches.match('/offline.html')||new Response('Offline',{status:503})}}async function cacheMatchAndUpdate(request,cache){const res=await fetch(request);if(res.ok){await cache.put(request,res.clone())}return res}function maybeRefreshBackground(request,cache){fetch(request).then(res=>res.ok&&cache.put(request,res.clone())).catch(()=>{})}async function cleanupOldCaches(){const names=await caches.keys();const currentVersions=names.filter(n=>n.startsWith(`${CONFIG.CACHE_PREFIX }-v`)).map(n=>parseInt(n.split('-v')[1])).sort((a,b)=>b-a);const keep=new Set(currentVersions.slice(0,2));await Promise.all(names.filter(n=>n.startsWith(`${CONFIG.CACHE_PREFIX }-`)&&!keep.has(parseInt(n.split('-v')[1]))).map(n=>caches.delete(n)))}async function getDBConnection(){if(dbConnection){return dbConnection}dbConnection=await new Promise((resolve,reject)=>{const req=indexedDB.open(CONFIG.DB_NAME,CONFIG.DB_VERSION);req.onupgradeneeded=e=>{const db=e.target.result;if(!db.objectStoreNames.contains(CONFIG.STORE_NAME)){db.createObjectStore(CONFIG.STORE_NAME,{keyPath:'version'})}};req.onsuccess=()=>resolve(req.result);req.onerror=()=>reject(req.error)});return dbConnection}async function getLatestVersion(db){return new Promise(resolve=>{const tx=db.transaction(CONFIG.STORE_NAME,'readonly');const req=tx.objectStore(CONFIG.STORE_NAME).getAllKeys();req.onsuccess=()=>resolve(req.result?.length?Math.max(...req.result):0);req.onerror=()=>resolve(0)})}async function updateMetadata(db,fileList){return new Promise((resolve,reject)=>{const tx=db.transaction(CONFIG.STORE_NAME,'readwrite');tx.objectStore(CONFIG.STORE_NAME).put({version:fileList.version,timestamp:Date.now(),count:fileList.files.length});tx.oncomplete=()=>resolve();tx.onerror=()=>reject(tx.error)})}async function fetchWithTimeout(url,ms,bypassCache=false){const controller=new AbortController();const id=setTimeout(()=>controller.abort(),ms);const opts={signal:controller.signal,cache:bypassCache?'no-store':'default'};try{const res=await fetch(url,opts);clearTimeout(id);if(!res.ok){throw new Error(`HTTP ${res.status }`)}return await res.json()}catch(e){clearTimeout(id);if(e.name==='AbortError'){throw new Error('Timeout')}throw e}}function sleep(ms){return new Promise(r=>setTimeout(r,ms))}
